790 // Computes the boosting factor for complete unrolling.
791 // If fully unrolling the loop would save a lot of RolledDynamicCost, it would
792 // be beneficial to fully unroll the loop even if unrolledcost is large. We
793 // use (RolledDynamicCost / UnrolledCost) to model the unroll benefits to adjust
794 // the unroll threshold.
795 static unsigned getFullUnrollBoostingFactor(const EstimatedUnrollCost &Cost,
796                                             unsigned MaxPercentThresholdBoost) {
797   if (Cost.RolledDynamicCost >= std::numeric_limits<unsigned>::max() / 100)
798     return 100;
799   else if (Cost.UnrolledCost != 0)
800     // The boosting factor is RolledDynamicCost / UnrolledCost
801     return std::min(100 * Cost.RolledDynamicCost / Cost.UnrolledCost,
802                     MaxPercentThresholdBoost);
803   else
804     return MaxPercentThresholdBoost;
805 }
