1379   if (RemainderLoop) {
1380     std::optional<MDNode *> RemainderLoopID =
1381         makeFollowupLoopID(OrigLoopID, {LLVMLoopUnrollFollowupAll,
1382                                         LLVMLoopUnrollFollowupRemainder});
1383     if (RemainderLoopID)
1384       RemainderLoop->setLoopID(*RemainderLoopID);
1385   }
1386 
1387   if (UnrollResult != LoopUnrollResult::FullyUnrolled) {
1388     std::optional<MDNode *> NewLoopID =
1389         makeFollowupLoopID(OrigLoopID, {LLVMLoopUnrollFollowupAll,
1390                                         LLVMLoopUnrollFollowupUnrolled});
1391     if (NewLoopID) {
1392       L->setLoopID(*NewLoopID);
1393 
1394       // Do not setLoopAlreadyUnrolled if loop attributes have been specified
1395       // explicitly.
1396       return UnrollResult;
1397     }
1398   }
1399 
1400   // If loop has an unroll count pragma or unrolled by explicitly set count
1401   // mark loop as unrolled to prevent unrolling beyond that requested.
1402   if (UnrollResult != LoopUnrollResult::FullyUnrolled && IsCountSetExplicitly)
1403     L->setLoopAlreadyUnrolled();
1404 
1405   return UnrollResult;
1406 }
