1280   // Don't unroll reductions with constant ops; those can be folded to a
1281   // single induction update.
1282   if (any_of(cast<Instruction>(Phi.getIncomingValueForBlock(L->getLoopLatch()))
1283                  ->operands(),
1284              IsaPred<Constant>))
1285     return std::nullopt;
1286 
1287   BasicBlock *Latch = L->getLoopLatch();
1288   if (!Latch ||
1289       !is_contained(
1290           cast<Instruction>(Phi.getIncomingValueForBlock(Latch))->operands(),
1291           &Phi))
